const resp = $.steps.scrapeUrl.response || {};
const data = resp.data || {};
const md = data.markdown || '';
const url = $.input.url;

let prompt = 'You are a web scraping data extraction specialist. Analyze the following scraped webpage content and extract ALL structured data items you find (products, listings, entries, rows, records, etc).\n\n';
prompt += 'SOURCE URL: ' + url + '\n\n';
prompt += 'SCRAPED CONTENT:\n' + md.slice(0, 8000) + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Identify the repeating data pattern on the page (e.g. product listings, directory entries, table rows)\n';
prompt += '- Extract every item with all available fields (title, price, description, rating, link, etc.)\n';
prompt += '- Normalize prices to numbers where possible\n';
prompt += '- Sort items by the most relevant numeric field (price, rating, etc.) descending\n\n';
prompt += 'Return ONLY valid JSON in this format:\n';
prompt += '{\n';
prompt += '  "pageTitle": "title of the page",\n';
prompt += '  "itemType": "what kind of items were found",\n';
prompt += '  "totalItems": 0,\n';
prompt += '  "headers": ["column1", "column2", "column3"],\n';
prompt += '  "items": [\n';
prompt += '    { "column1": "value", "column2": "value", "column3": "value" }\n';
prompt += '  ],\n';
prompt += '  "summary": "brief one-line summary of what was extracted"\n';
prompt += '}';

return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { items: [], headers: [], summary: raw, pageTitle: 'Scraped Data', totalItems: 0 }; }

const ai = $.steps.parseAI.output;
const items = ai.items || [];
const headers = ai.headers || (items.length > 0 ? Object.keys(items[0]) : ['Data']);
const date = new Date().toISOString().split('T')[0];

const sheetData = items.map((item, i) => {
  const row = { '#': i + 1 };
  headers.forEach(h => { row[h] = item[h] !== undefined ? String(item[h]) : ''; });
  return row;
});

let csvLines = ['#,' + headers.join(',')];
items.forEach((item, i) => {
  const vals = headers.map(h => {
    const v = item[h] !== undefined ? String(item[h]) : '';
    return '"' + v.replace(/"/g, '""') + '"';
  });
  csvLines.push((i + 1) + ',' + vals.join(','));
});
const csvBody = csvLines.join('\n');

let emailBody = '<h2>Scraped Data Report</h2>';
emailBody += '<p><strong>Source:</strong> ' + $.input.url + '</p>';
emailBody += '<p><strong>Date:</strong> ' + date + '</p>';
emailBody += '<p><strong>Items found:</strong> ' + items.length + '</p>';
emailBody += '<p>' + (ai.summary || '') + '</p>';
emailBody += '<table border="1" cellpadding="4" cellspacing="0"><tr>';
headers.forEach(h => { emailBody += '<th>' + h + '</th>'; });
emailBody += '</tr>';
items.slice(0, 50).forEach(item => {
  emailBody += '<tr>';
  headers.forEach(h => { emailBody += '<td>' + (item[h] !== undefined ? item[h] : '') + '</td>'; });
  emailBody += '</tr>';
});
emailBody += '</table>';
if (items.length > 50) emailBody += '<p><em>Showing first 50 of ' + items.length + ' items. Full data in Google Sheets.</em></p>';

return { sheetData, csvBody, emailBody, pageTitle: ai.pageTitle || 'Scraped Data', itemCount: items.length, date };
